from ctypes import c_void_p, c_long, c_int
import torch
import triton
import triton.language as tl
from torch._C import _cuda_getCurrentRawStream as get_raw_stream

aten = torch.ops.aten

@triton.autotune(
    configs=[
        triton.Config({"XBLOCK": 128, "YBLOCK": 128, "R0_BLOCK": 32}, num_stages=2, num_warps=4),
    ],
    key=[],
)
@triton.jit
def triton_red_fused_sum_0(in_ptr0, in_ptr1, out_ptr0, YBLOCK: tl.constexpr, XBLOCK: tl.constexpr, R0_BLOCK: tl.constexpr):
    yindex = tl.program_id(1) * YBLOCK + tl.arange(0, YBLOCK)[None, :, None]
    xindex = tl.program_id(0) * XBLOCK + tl.arange(0, XBLOCK)[:, None, None]
    _tmp4 = tl.full([XBLOCK, YBLOCK], 0, tl.float32)

    for r0_offset in range(0, 8192, R0_BLOCK):
        r0_index = r0_offset + tl.arange(0, R0_BLOCK)[None, None, :]
        tmp0 = tl.load(in_ptr0 + (r0_index + 8192 * yindex))
        tmp1 = tl.load(in_ptr1 + (xindex + 8192 * r0_index))
        _tmp4 += tl.dot(tl.reshape(tmp1, [XBLOCK, R0_BLOCK]), tl.trans(tl.reshape(tmp0, [YBLOCK, R0_BLOCK])))

    tl.store(out_ptr0 + (xindex + 8192 * yindex), _tmp4[:,:,None])


def call(args):
    arg0_1, arg1_1 = args
    buf0 = torch.empty_strided((8192, 8192), (8192, 1), dtype=torch.float16, device='cuda')
    grid = lambda meta: (triton.cdiv(8192, meta["XBLOCK"]), triton.cdiv(8192, meta["YBLOCK"]))
    triton_red_fused_sum_0[grid](arg0_1, arg1_1, buf0)
    return (buf0, )


def benchmark_compiled_module(times=10, repeat=10):
    from torch._dynamo.testing import rand_strided
    from torch._inductor.utils import print_performance

    arg0_1 = rand_strided((8192, 8192), (8192, 1), device='cuda:0', dtype=torch.float16)
    arg1_1 = rand_strided((8192, 8192), (8192, 1), device='cuda:0', dtype=torch.float16)
    fn = lambda: call([arg0_1, arg1_1])
    return print_performance(fn, times=times, repeat=repeat)


if __name__ == "__main__":
    from torch._inductor.wrapper_benchmark import compiled_module_main
    compiled_module_main('None', benchmark_compiled_module)

