#include "Halide.h"
#include <stdio.h>

using namespace Halide;

class F16BugGenerator : public Halide::Generator<F16BugGenerator> {
public:
  Input<Buffer<>> input{"input", 2};
  Output<Buffer<>> output{"output", 2};

  Var x, y;

  void generate() {
    Expr val = cast(output.type(), input(x, y) + 1.f);
    Expr clamp_val = clamp(val, cast(output.type(), 0), cast(output.type(), 1));

    output(x, y) = cast(output.type(), select(clamp_val > 1, cast<float>(abs(clamp_val)), cast<float>(fast_pow(clamp_val, 1.f / 2.2f))));

    if (get_target().has_gpu_feature()) {
      printf("GPU schedule\n");
      Var xi, xo, yi, yo;
      output.compute_root()
          .gpu_tile(x, y, xo, yo, xi, yi, 8, 32);
    }
  }
};

HALIDE_REGISTER_GENERATOR(F16BugGenerator, f16_bug_generator)

#include "Halide.h"

using namespace Halide;

class MyGen : public Generator<MyGen> {
public:
  Input<Buffer<float, 1>> in{"input"};
  Output<Buffer<float, 1>> out{"output"};
  Var x, tx;

  void generate() {
    out(x) = cast<float>(in(x) >= 0) - cast<float>(in(x) < 0);
    out.gpu_tile(x, tx, 16)
      .vectorize(tx, 4);
  }

};

HALIDE_REGISTER_GENERATOR(MyGen, mygen)

#include "Halide.h"

using namespace Halide;

class HalfFloatMatMul : public Halide::Generator<HalfFloatMatMul> {
public:
    Input<Buffer<float16_t, 2>> A{"A"};
    Input<Buffer<float16_t, 2>> B{"B"};

    Output<Buffer<float, 2>> output{"C"};

    void generate() {
        RDom r(0, A.dim(0).extent(), "r");
    	matmul(x, y) += cast<float>(A(r, y)) * cast<float>(B(r, x));
        output(x, y) = matmul(x, y);
    }

    void schedule() {
        if (using_autoscheduler()) {
            A.set_estimates({{0, 1024}, {0, 1024}});
            B.set_estimates({{0, 1024}, {0, 1024}});
            output.set_estimates({{0, 1024}, {0, 1024}});
        } else {
            matmul.compute_root();
        }
    }

private:
    Func matmul;
    Var x{"x"}, y{"y"};
};

HALIDE_REGISTER_GENERATOR(HalfFloatMatMul, my_gen)

