import triton

@triton.jit
def _kernel(C):
    C = C + tl.arange(0, 128)
    acc = tl.zeros((128,), dtype=tl.float32)
    
    for _ in range(1):
        for _ in range(1):
            acc += 1
    
    tl.store(C, acc, mask=True)

class func_(torch.autograd.Function):
    kernel = _kernel

    @staticmethod
    def _call():
        c = torch.empty((128), device='cuda')
        grid = lambda META: (1,)
        _kernel[grid](c)
        return c

    @staticmethod
    def forward(ctx):
        return func_._call()

func = func_.apply
a = func()

