#include "Halide.h"
using namespace Halide;

int main() {
    Func input("input");
    Func local_sum("local_sum");
    Func blurry("blurry");
    Var x("x"), y("y");
    input(x, y) = 2 * x + 5 * y;
    RDom r(-2, 5, -2, 5);
    local_sum(x, y) = 0;
    local_sum(x, y) += input(x + r.x, y + r.y);
    blurry(x, y) = cast<int32_t>(local_sum(x, y) / 25);
    {
        Var yo, yi, xo, xi, xio, xii, xiio, xiii;
        blurry.split(y, yo, yi, 4, TailStrategy::Auto).split(x, xo, xi, 1, TailStrategy::Auto).split(xi, xio, xii, 4, TailStrategy::GuardWithIf).split(xii, xiio, xiii, 1, TailStrategy::RoundUp);
        local_sum.compute_at(blurry, xiio);
        input.compute_at(blurry, xiio);
        input.store_root();
        Pipeline p({blurry});
        Buffer<int> buf = p.realize({128, 128});
    }
    return 0;
}

