import triton
import triton.language as tl

@triton.jit
def foo(in_ptr):
    offs = tl.arange(0, 16) # (128)
    ptrs = in_ptr + offs[:, None] * 16 + offs[None, :]
    for _ in range(2):
        p = tl.load(ptrs)
        for _ in range(2):
            a = tl.load(ptrs)
            b = tl.dot(a, tl.trans(p))
            tl.store(ptrs, b)

