Var c("c");

class Debug : public Generator<Debug> {
 public:
  GeneratorParam<bool> extra_compute{"extra_compute", false};
  GeneratorParam<bool> extra_schedule{"extra_schedule", false};

  // Input image.
  Input<Buffer<float>> input{"input", 3};

  Output<Buffer<float>> output{"output", 3};

  void generate() {
    // These functions have no effect to the final output value, but will
    // trigger the scheduling bug
    Func masks_up_x("masks_up_x");
    Func masks_up_y("masks_up_y");

    masks_up_x(x, y, z) = 0.f;

    Expr yv = cast<float>(y) - 0.5f;
    Expr yi = cast<int>(floor(yv));
    masks_up_y(x, y, z) = masks_up_x(x, yi, z);

    if (extra_compute) {
      // Add masks_up_y, which should not change the output at all
      output(x, y, c) = input(x, y, c) + masks_up_y(x, y, 0);
    } else {
      output(x, y, c) = input(x, y, c);
    }

    // Schedule
    if (!using_autoscheduler()) {
      if (get_target().has_gpu_feature()) {
        Var xi, xo, yi, yo;
        output.compute_root()
            .reorder(c, x, y)
            .bound(c, 0, 3)
            .unroll(c)
            .gpu_tile(x, y, xo, yo, xi, yi, 8, 32);

        if (extra_schedule) {
          // This schedule generates a Metal GPU kernel that does not compute anything
          masks_up_x.compute_at(output, xo).unroll(z).gpu_threads(x, y);
        }

      } else {
      }
    }

    // Estimates
    {}
  }
};
}  // namespace

