def compute():
    a = wp.tile_arange(-10, 10, dtype=int)

    print(a)


wp.launch_tiled(compute, dim=[1], inputs=[], block_dim=16)

import warp as wp

@wp.func
def test_func():
    stop = wp.bool(False)
    while not stop:
        stop = True
        break

@wp.kernel
def test_kernel():
    test_func()

wp.init()
wp.launch(test_kernel, dim=1)

import warp as wp


@wp.kernel
def kernel():
    i, j = wp.tid()
    mod(i, j + 1)


@wp.func
def mod(a: int, b: int) -> tuple[int, int]:
    return a // b, a % b


wp.launch(kernel, dim=(100, 10))

@wp.kernel
def kernel(
    idx: wp.array(dtype=wp.uint32)
):
    wp.atomic_min(idx, wp.uint32(0), wp.uint32(0))


idx = wp.zeros(123, dtype=wp.uint32)
wp.launch(kernel, dim=1, outputs=(idx,))

